insert into public.waypoints (id,title,title_en,description,description_en,tipo,routes,species_ids,lng,lat,photo) values ('punto_1','Casa','House','La casa principal es el corazón de Cantares y el punto de partida de los recorridos. El nombre de la reserva nace de los «cantares» del bosque: el coro de aves, ranas, grillos, vientos y cascadas que suena de día y de noche.','The main house is the heart of Cantares and the starting point of the trails. The reserve''s name comes from the «cantares» (songs) of the forest: the chorus of birds, frogs, crickets, wind and waterfalls that plays day and night.','servicio',array['agua','regeneracion','arboles','paisaje','aves','nocturno','flora']::text[],'{}'::text[],-75.4497941638855,5.082506128567199,null) on conflict (id) do nothing;
insert into public.waypoints (id,title,title_en,description,description_en,tipo,routes,species_ids,lng,lat,photo) values ('punto_2','Mirador Nido del Águila','Eagle''s Nest Lookout','Desde este mirador, con paciencia, se alcanza a ver a la distancia el nido del águila crestada de montaña (Spizaetus isidori), la segunda águila más amenazada de los Andes. Comparte la cima de la cadena alimenticia con el puma.','From this lookout, with patience, you can spot in the distance the nest of the black-and-chestnut eagle (Spizaetus isidori), the second most threatened eagle in the Andes. It shares the top of the food chain with the puma.','mirador',array['aves']::text[],array['spizaetus isidori']::text[],-75.44970763637757,5.08184651999299,null) on conflict (id) do nothing;
insert into public.waypoints (id,title,title_en,description,description_en,tipo,routes,species_ids,lng,lat,photo) values ('punto_3','Cascada','Waterfall','Una de las cerca de cuatro cascadas naturales que alimentan la quebrada Olivares que, junto con la cuenca del río Blanco, abastece de agua al 35% de Manizales. En sus peñas, la humedad constante da refugio a varias especies de ranas.','One of about four natural waterfalls feeding the Olivares creek which, together with the Río Blanco basin, supplies water to 35% of Manizales. Its constantly humid rock faces shelter several frog species.','agua',array['agua']::text[],'{}'::text[],-75.44892030786701,5.080244339390315,null) on conflict (id) do nothing;
insert into public.waypoints (id,title,title_en,description,description_en,tipo,routes,species_ids,lng,lat,photo) values ('punto_4','Mirador 1','Lookout 1','Un balcón sobre la reserva. El paisaje de Cantares es una «huella en el tiempo» que evidencia la restauración de suelos, bosques y fuentes de agua.','A balcony over the reserve. The Cantares landscape is a «footprint in time» that shows the restoration of soils, forests and water sources.','mirador',array['paisaje','aves']::text[],'{}'::text[],-75.45050978594683,5.082969876640846,null) on conflict (id) do nothing;
insert into public.waypoints (id,title,title_en,description,description_en,tipo,routes,species_ids,lng,lat,photo) values ('punto_5','Mirador 2','Lookout 2','Otro punto para contemplar la cuenca. Al atardecer suelen pasar bandadas de palomas collarejas (Patagioenas fasciata), a veces de más de 100 individuos.','Another spot to take in the watershed. At dusk, flocks of band-tailed pigeons (Patagioenas fasciata) often pass by, sometimes more than 100 birds.','mirador',array['paisaje','aves']::text[],'{}'::text[],-75.45186037650333,5.08250402618,null) on conflict (id) do nothing;
insert into public.waypoints (id,title,title_en,description,description_en,tipo,routes,species_ids,lng,lat,photo) values ('punto_6','Bosque de Sietecueros','Andesanthus lepidotus foest','Un bosque dominado por el sietecueros (Andesanthus lepidotus, antes Tibouchina lepidota), de flores moradas. Aquí se siembran árboles nativos como el pino colombiano (Retrophyllum rospigliosii), el roble andino (Quercus humboldtii) y la palma de cera quindiana (Ceroxylon quindiuense).','A forest dominated by the purple-flowered sietecueros (Andesanthus lepidotus, formerly Tibouchina lepidota). Native trees are planted here — Colombian pine (Retrophyllum rospigliosii), Andean oak (Quercus humboldtii) and the Quindío wax palm (Ceroxylon quindiuense).','flora',array['agua','aves','regeneracion']::text[],array['andesanthus lepidotus']::text[],-75.45087556437744,5.081576435299737,null) on conflict (id) do nothing;
insert into public.waypoints (id,title,title_en,description,description_en,tipo,routes,species_ids,lng,lat,photo) values ('punto_7','Nido de Águila','Eagle''s Nest','El águila crestada de montaña (Spizaetus isidori), llamada «Guamán», anida en estas pendientes. Casi cada día una pareja y su juvenil planean sobre la reserva aprovechando las corrientes térmicas: «autopistas de aire» que reducen su esfuerzo al volar.','The black-and-chestnut eagle (Spizaetus isidori), locally «Guamán», nests on these slopes. Almost daily a pair and their juvenile soar over the reserve riding thermals — «air highways» that let them fly with little effort.','avistamiento',array['aves']::text[],array['spizaetus isidori']::text[],-75.45286472577175,5.080023452790146,null) on conflict (id) do nothing;
insert into public.waypoints (id,title,title_en,description,description_en,tipo,routes,species_ids,lng,lat,photo) values ('punto_8','Cabaña','Cabin','Desde la cabaña principal se ofrece la guianza e interpretación ambiental. Es el mejor lugar para descansar, orientarse y decidir qué sendero recorrer.','The main cabin is the base for guided walks and environmental interpretation — the best place to rest, get your bearings and choose which trail to take.','servicio','{}'::text[],'{}'::text[],-75.44961908739918,5.082891745189303,null) on conflict (id) do nothing;
insert into public.waypoints (id,title,title_en,description,description_en,tipo,routes,species_ids,lng,lat,photo) values ('punto_10','Jardin de los Colibríes','Hummingbird Garden','Un jardín ornamentado con flores que tradicionalmente decoran las fincas de la región —fucsias, abutilones, verbenas, zarcillos— y que atraen a las más de 16 especies de colibríes registradas en la reserva.','A garden of flowers that traditionally adorn the region''s farms —fuchsias, abutilons, verbenas— attracting the 16-plus hummingbird species recorded in the reserve.','avistamiento',array['aves']::text[],'{}'::text[],-75.44979690879542,5.082294328960689,null) on conflict (id) do nothing;
insert into public.waypoints (id,title,title_en,description,description_en,tipo,routes,species_ids,lng,lat,photo) values ('punto_11','Vivero','nursery-garden','El invernadero funciona como «laboratorio» para reproducir in situ la flora nativa de la zona. Es el motor de la reforestación activa que vincula al visitante con la conservación.','The greenhouse works as a «laboratory» to propagate the area''s native flora in situ. It powers the active reforestation that connects visitors to conservation.','flora',array['regeneracion','flora']::text[],'{}'::text[],-75.44931452445408,5.082702999782367,null) on conflict (id) do nothing;
insert into public.waypoints (id,title,title_en,description,description_en,tipo,routes,species_ids,lng,lat,photo) values ('punto_12','Tanques de Agua','Water Tanks','Parte del sistema que capta el agua de las quebradas de Cantares. Toda esta cuenca alimenta el río Blanco, del que depende buena parte del agua potable de Manizales.','Part of the system that captures water from the Cantares creeks. This whole basin feeds the Río Blanco, on which much of Manizales'' drinking water depends.','agua',array['agua']::text[],'{}'::text[],-75.44969425334372,5.083014954543437,null) on conflict (id) do nothing;
insert into public.waypoints (id,title,title_en,description,description_en,tipo,routes,species_ids,lng,lat,photo) values ('punto_13','Avistamiento de un Puma','Puma sighting','Las cámaras trampa registraron aquí al puma o león de montaña (Puma concolor), tope de la red alimenticia junto al águila crestada. Su presencia muestra por qué importa conservar los corredores biológicos de los Andes.','Camera traps recorded the puma or mountain lion (Puma concolor) here — top of the food web alongside the crested eagle. Its presence shows why the Andes'' biological corridors are worth conserving.','avistamiento','{}'::text[],array['puma sighting']::text[],-75.45359350493767,5.080576564189988,null) on conflict (id) do nothing;
insert into public.waypoints (id,title,title_en,description,description_en,tipo,routes,species_ids,lng,lat,photo) values ('punto_14','Mirador 3 Cuidad de Manizales','Viewpoint Manizales','Desde aquí se abre la vista hacia la ciudad de Manizales. El mirador conecta el bosque en recuperación de Cantares con el paisaje urbano que depende de su agua.','This lookout opens toward the city of Manizales, linking the recovering forest of Cantares with the urban landscape that depends on its water.','mirador',array['paisaje']::text[],'{}'::text[],-75.45370433352923,5.080971888984172,null) on conflict (id) do nothing;
insert into public.waypoints (id,title,title_en,description,description_en,tipo,routes,species_ids,lng,lat,photo) values ('punto_15','Avistamiento Rana de Chocolate','cordillera central tree frog sighting','La rana de la cordillera central (Hyloscirtus larinopygion) vive ligada a las quebradas de aguas limpias y frías. La humedad constante del bosque y las cascadas son su refugio.','The central cordillera tree frog (Hyloscirtus larinopygion) lives tied to clean, cold streams. The forest''s constant humidity and the waterfalls are its refuge.','avistamiento','{}'::text[],array['hyloscirtus larinopygion']::text[],-75.44979913767904,5.082631026134644,null) on conflict (id) do nothing;
insert into public.waypoints (id,title,title_en,description,description_en,tipo,routes,species_ids,lng,lat,photo) values ('punto_16','Avistamiento Tinamú y Tucán','Tinamú and Toucan Sighting','El tinamú leonado (Nothocercus julius), terrestre y difícil de ver, canta con fuerza al amanecer. Lo acompaña el tucán pechiazul (Andigena nigrirostris), gran dispersor de semillas del bosque montano.','The tawny-breasted tinamou (Nothocercus julius), a shy ground bird, sings loudly at dawn. Alongside it, the grey-breasted mountain toucan (Andigena nigrirostris) is a key seed disperser of the montane forest.','avistamiento',array['aves']::text[],array['nothocercus julius','andigena nigrirostris']::text[],-75.45357527194629,5.082074989329771,null) on conflict (id) do nothing;
insert into public.waypoints (id,title,title_en,description,description_en,tipo,routes,species_ids,lng,lat,photo) values ('punto_15b','Comederos de Aves','Bird Feeders','Los comederos y el jardín de flores tradicionales de la región concentran la actividad de las aves. Aquí se han registrado más de 16 especies de colibríes, entre ellas el rumbito pechiblanco (Chaetocercus mulsant), el colibrí más pequeño de Colombia.','The feeders and the garden of traditional regional flowers draw intense bird activity. Over 16 hummingbird species have been recorded here, including the white-bellied woodstar (Chaetocercus mulsant), Colombia''s smallest hummingbird.','avistamiento',array['aves']::text[],'{}'::text[],-75.44995617598946,5.0822644612391,null) on conflict (id) do nothing;
